// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title MockGoodDollar
 * @dev A simple ERC-20 mock for testing SwipeGigPool on Celo Sepolia.
 *      Mints an initial supply to the deployer.
 */
contract MockGoodDollar {
    string public constant name = "Mock GoodDollar";
    string public constant symbol = "mG$";
    uint8 public constant decimals = 18;

    uint256 public totalSupply;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    constructor(uint256 _initialSupply) {
        totalSupply = _initialSupply;
        balanceOf[msg.sender] = _initialSupply;
        emit Transfer(address(0), msg.sender, _initialSupply);
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        require(balanceOf[msg.sender] >= amount, "Insufficient balance");
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;
        emit Transfer(msg.sender, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        require(balanceOf[from] >= amount, "Insufficient balance");
        require(allowance[from][msg.sender] >= amount, "Insufficient allowance");
        balanceOf[from] -= amount;
        allowance[from][msg.sender] -= amount;
        balanceOf[to] += amount;
        emit Transfer(from, to, amount);
        return true;
    }
}

contracts/SwipeGigApplications.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

abstract contract Ownable {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    constructor(address initialOwner) {
        _owner = initialOwner;
        emit OwnershipTransferred(address(0), initialOwner);
    }

    function owner() public view virtual returns (address) {
        return _owner;
    }

    modifier onlyOwner() {
        require(owner() == msg.sender, "Ownable: caller is not the owner");
        _;
    }

    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}

contract SwipeGigApplications is Ownable {
    enum ApplicationStatus {
        APPLIED,
        INTERVIEWING,
        OFFERED,
        REJECTED,
        WITHDRAWN
    }

    struct ApplicationRecord {
        uint256 id;
        string jobId;
        string companyName;
        ApplicationStatus status;
        uint256 timestamp;
    }

    mapping(address => ApplicationRecord[]) private userApplications;
    uint256 public nextApplicationId;

    event ApplicationRecorded(address indexed user, uint256 indexed id, string jobId, string companyName, uint256 timestamp);
    event StatusUpdated(address indexed user, uint256 indexed id, ApplicationStatus status, uint256 timestamp);

    constructor() Ownable(msg.sender) {}

    function recordApplication(address user, string calldata jobId, string calldata companyName) external onlyOwner returns (uint256) {
        require(user != address(0), "Invalid user address");

        uint256 appId = nextApplicationId++;

        userApplications[user].push(ApplicationRecord({
            id: appId,
            jobId: jobId,
            companyName: companyName,
            status: ApplicationStatus.APPLIED,
            timestamp: block.timestamp
        }));

        emit ApplicationRecorded(user, appId, jobId, companyName, block.timestamp);
        return appId;
    }

    function updateStatus(address user, uint256 appId, ApplicationStatus status) external onlyOwner {
        ApplicationRecord[] storage apps = userApplications[user];
        bool found = false;

        for (uint256 i = 0; i < apps.length; i++) {
            if (apps[i].id == appId) {
                apps[i].status = status;
                found = true;
                emit StatusUpdated(user, appId, status, block.timestamp);
                break;
            }
        }

        require(found, "Application not found");
    }

    function getApplications(address user) external view returns (ApplicationRecord[] memory) {
        return userApplications[user];
    }
}

contracts/SwipeGigPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

abstract contract Ownable {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    constructor(address initialOwner) {
        _owner = initialOwner;
        emit OwnershipTransferred(address(0), initialOwner);
    }

    function owner() public view virtual returns (address) {
        return _owner;
    }

    modifier onlyOwner() {
        require(owner() == msg.sender, "Ownable: caller is not the owner");
        _;
    }

    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}

abstract contract ReentrancyGuard {
    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    uint256 private _status;

    constructor() {
        _status = _NOT_ENTERED;
    }

    modifier nonReentrant() {
        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }
}

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

contract SwipeGigPool is Ownable, ReentrancyGuard {
    IERC20 public goodDollarToken;

    uint256 public weeklyClaimAmount;
    uint256 public activityThreshold;

    mapping(address => uint256) public lastClaimedTimestamp;
    mapping(address => uint256) public weeklyActivity;

    event Claimed(address indexed user, uint256 amount, uint256 timestamp);
    event ActivityLogged(address indexed user, uint256 newActivityCount, uint256 timestamp);
    event PoolFunded(address indexed donor, uint256 amount, uint256 timestamp);

    constructor(
        address _goodDollarToken,
        uint256 _weeklyClaimAmount,
        uint256 _activityThreshold
    ) Ownable(msg.sender) {
        goodDollarToken = IERC20(_goodDollarToken);
        weeklyClaimAmount = _weeklyClaimAmount;
        activityThreshold = _activityThreshold;
    }

    function setParams(uint256 _weeklyClaimAmount, uint256 _activityThreshold) external onlyOwner {
        weeklyClaimAmount = _weeklyClaimAmount;
        activityThreshold = _activityThreshold;
    }

    function logActivity(address user, uint256 count) external onlyOwner {
        weeklyActivity[user] += count;
        emit ActivityLogged(user, weeklyActivity[user], block.timestamp);
    }

    function resetActivity(address user) external onlyOwner {
        weeklyActivity[user] = 0;
    }

    function fundPool(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be greater than zero");
        require(goodDollarToken.transferFrom(msg.sender, address(this), amount), "Transfer failed");
        emit PoolFunded(msg.sender, amount, block.timestamp);
    }

    function claimWeeklyReward() external nonReentrant {
        require(block.timestamp >= lastClaimedTimestamp[msg.sender] + 7 days, "Claim limit is weekly");
        require(weeklyActivity[msg.sender] >= activityThreshold, "Insufficient activity count");

        uint256 poolBalance = goodDollarToken.balanceOf(address(this));
        require(poolBalance >= weeklyClaimAmount, "Insufficient pool funding");

        lastClaimedTimestamp[msg.sender] = block.timestamp;
        weeklyActivity[msg.sender] = 0;

        require(goodDollarToken.transfer(msg.sender, weeklyClaimAmount), "Transfer failed");

        emit Claimed(msg.sender, weeklyClaimAmount, block.timestamp);
    }
}

contracts/SwipeGigRewards.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

abstract contract Ownable {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    constructor(address initialOwner) {
        _owner = initialOwner;
        emit OwnershipTransferred(address(0), initialOwner);
    }

    function owner() public view virtual returns (address) {
        return _owner;
    }

    modifier onlyOwner() {
        require(owner() == msg.sender, "Ownable: caller is not the owner");
        _;
    }

    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}

abstract contract ReentrancyGuard {
    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    uint256 private _status;

    constructor() {
        _status = _NOT_ENTERED;
    }

    modifier nonReentrant() {
        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }
}

contract SwipeGigRewards is Ownable, ReentrancyGuard {
    struct RewardRecord {
        uint256 amount;
        string triggerType;
        uint256 timestamp;
    }

    mapping(address => RewardRecord[]) private userRewards;
    mapping(address => uint256) public totalEarned;

    address public backendSigner;

    event RewardMinted(address indexed user, uint256 amount, string triggerType, uint256 timestamp);

    constructor(address _backendSigner) Ownable(msg.sender) {
        backendSigner = _backendSigner;
    }

    modifier onlyBackendOrOwner() {
        require(msg.sender == owner() || msg.sender == backendSigner, "Unauthorized");
        _;
    }

    function setBackendSigner(address _backendSigner) external onlyOwner {
        backendSigner = _backendSigner;
    }

    function recordReward(address user, uint256 amount, string calldata triggerType) external onlyBackendOrOwner nonReentrant {
        require(user != address(0), "Invalid user address");
        require(amount > 0, "Amount must be greater than zero");

        userRewards[user].push(RewardRecord({
            amount: amount,
            triggerType: triggerType,
            timestamp: block.timestamp
        }));

        totalEarned[user] += amount;

        emit RewardMinted(user, amount, triggerType, block.timestamp);
    }

    function getRewardHistory(address user) external view returns (RewardRecord[] memory) {
        return userRewards[user];
    }
}

